LOCK TABLES `categories` WRITE;
/*!40000 ALTER TABLE `categories` DISABLE KEYS */;
INSERT INTO `categories` VALUES (1,'Zombie','Creazioni ispirate ai non-morti: colori verdi malsani, sapori marcescenti e dolcemente putrefatti. Ogni morso è un ritorno dalla tomba. Perfetti per chi non si accontenta di sapori ordinari e vuole qualcosa di... decompostamente buono.','Gusti putrefatti e disgustosamente irresistibili','theme'),(2,'Fantasmi','Gelati eterei e pallidi come apparizioni notturne. Gusti lattiginosi, vaporosi, che si sciolgono in bocca lasciando solo un brivido freddo. Li vedi, li assaggi... e poi spariscono.','Gusti evanescenti che appaiono e scompaiono','theme'),(3,'Serial Killer','Per i palati più spietati. Gusti decisi, taglienti, senza pietà. Ogni cucchiaio è un colpo secco di sapore intenso da cui non si torna indietro. Non dire che non ti avevamo avvisato.','Gusti intensi e spietati, senza via di scampo','theme'),(4,'Super Cattivi','Ispirati ai villain più iconici della storia. Grandiosi, sopra le righe, con un tocco di malvagità raffinata. Perché essere buoni è sopravvalutato, soprattutto quando si parla di gelato.','Gusti malvagi e iconici per veri antagonisti','theme'),(5,'Vampiri','Rossi come il sangue, dolci come la seduzione. Gusti intensi a base di frutti scuri, melograno e ciliegia nera. Ogni assaggio è un morso nel collo... ma in versione dessert.','Gusti rosso sangue, seducenti e irresistibili','theme'),(6,'Coni','Una cialda croccante e maledetta che racchiude il gelato più oscuro che tu abbia mai osato assaggiare. Ogni morso è un patto col diavolo: una volta cominciato, non puoi smettere. Scegli il tuo lato oscuro e addentalo senza rimorsi.','Cialda croccante e maledetta per i più coraggiosi','product_type'),(7,'Coppette','Il terrore servito con eleganza, cucchiaino dopo cucchiaino. Nelle nostre coppette il male si assapora lentamente, in tutta la sua oscura perfezione. Per chi vuole vivere l esperienza horror fino all ultimo boccone.','Il terrore servito con eleganza, cucchiaino dopo cucchiaino','product_type'),(8,'Granite','Fredde come la morte, granulari come la terra smossa a mezzanotte. Le nostre granite nascondono un anima oscura sotto una superficie innocente. Un brivido gelato che sale lungo la schiena ad ogni sorso.','Fredde come la morte, oscure come la mezzanotte','product_type'),(9,'Gusti Speciali','Creazioni nate nelle ore più buie, pensate per chi non si accontenta dell ordinario. Ingredienti insoliti, combinazioni proibite e sapori che nessun essere umano dovrebbe conoscere. Hai il coraggio di assaggiarli?','Combinazioni proibite per palati senza paura','product_type'),(10,'Limited Edition','Appaiono senza preavviso e spariscono nell oscurità prima che tu possa rendertene conto. Questi gusti maledetti sono disponibili per un tempo limitato, come ogni cosa preziosa e pericolosa. Non aspettare troppo... o sarà troppo tardi.','Gusti maledetti disponibili prima che sia troppo tardi','product_type');
/*!40000 ALTER TABLE `categories` ENABLE KEYS */;
UNLOCK TABLES;

