INSERT INTO `products` VALUES (1,'Cervello Marcio','Pistacchio e menta con colatura verde','Un gelato dal colore verdastro e inquietante, ispirato ai cervelli dei non-morti. Il pistacchio si mescola alla menta in un connubio disgustosamente irresistibile. Ogni morso è un ritorno dalla tomba.',3.50,'Latte, panna, zucchero, pistacchio, menta, colorante verde naturale','Latte, frutta a guscio',1,'https://example.com/cervello-marcio.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(2,'Putrefazione al Cioccolato','Cioccolato fondente con pezzi di biscotto al carbone','Scuro come una tomba aperta, intenso come l odore della terra smossa. Il cioccolato fondente incontra il biscotto al carbone vegetale per un risultato oscuro e irresistibile.',3.00,'Latte, panna, zucchero, cacao 70%, biscotto al carbone vegetale','Latte, glutine',1,'https://example.com/putrefazione-cioccolato.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(3,'Marcia Zombie','Anguria e lime con semi di chia neri','Fresco come una notte nei cimiteri, verde e rosso come i colori dei non-morti. L anguria incontra il lime in una granita che lascia i segni... di un morso.',2.50,'Acqua, zucchero, anguria, lime, semi di chia','Nessuno',1,'https://example.com/marcia-zombie.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(4,'Contagio Verde','Mela verde e zenzero con glassa fosforescente','Il virus del gusto che si diffonde morso dopo morso. La mela verde e lo zenzero creano un esplosione acida e pungente avvolta in una glassa verde fosforescente. Attento al contagio.',3.50,'Latte, panna, zucchero, mela verde, zenzero, colorante verde naturale','Latte',1,'https://example.com/contagio-verde.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(5,'Resurrezione','Frutti di bosco neri con ripieno cremoso alla vaniglia','Nato dalle ceneri del gusto ordinario, il Resurrezione esplode in un contrasto oscuro tra frutti di bosco neri e un cuore cremoso di vaniglia. Come tornare in vita, un morso alla volta.',4.50,'Latte, panna, zucchero, frutti di bosco, vaniglia bourbon','Latte',1,'https://example.com/resurrezione.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(6,'Apparizione','Cocco e lychee con glassa bianca lattiginosa','Bianco come un lenzuolo, leggero come un soffio d aria. Il cocco e il lychee si fondono in un gusto etereo che svanisce in bocca lasciando solo un brivido. Lo hai davvero assaggiato?',3.00,'Latte, panna, zucchero, cocco, lychee','Latte',1,'https://example.com/apparizione.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(7,'Spirito Pallido','Yogurt bianco e mandorla con polvere di vaniglia','Pallido e silenzioso come un fantasma che abita corridoi dimenticati. Lo yogurt bianco e la mandorla creano un gusto delicato che aleggia sul palato senza mai farsi davvero afferrare.',2.50,'Latte, yogurt, zucchero, mandorla, vaniglia','Latte, frutta a guscio',1,'https://example.com/spirito-pallido.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(8,'Nebbia di Mezzanotte','Limone bianco e fiori di sambuco','Una granita che sale dalla nebbia come un apparizione. Il limone bianco e i fiori di sambuco creano un gusto floreale e misterioso che avvolge i sensi e poi svanisce, lasciando solo un brivido.',2.50,'Acqua, zucchero, limone bianco, fiori di sambuco','Nessuno',1,'https://example.com/nebbia-mezzanotte.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(9,'Ectoplasma','Melone bianco e menta con colatura lattiginosa','Viscoso, misterioso, inspiegabilmente buono. L ectoplasma in versione gelato è un tripudio di melone bianco e menta avvolto in una colatura lattiginosa che cola lentamente come... meglio non sapere cosa.',3.50,'Latte, panna, zucchero, melone bianco, menta','Latte',1,'https://example.com/ectoplasma.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(10,'Ultimo Respiro','Pesca bianca e rosmarino con cuore gelato','Delicato come un sospiro, fugace come un ultima parola. La pesca bianca e il rosmarino si incontrano in un abbraccio aromatico e malinconico. Assaggialo prima che sparisca... per sempre.',4.00,'Latte, panna, zucchero, pesca bianca, rosmarino','Latte',1,'https://example.com/ultimo-respiro.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(11,'Lama Affilata','Lime e zenzero, un gusto che non perdona','Tagliente come un coltello, preciso come un colpo secco. Il lime e lo zenzero creano un esplosione acida e pungente che non lascia scampo al palato. Un gusto che colpisce senza preavviso.',3.00,'Acqua, zucchero, lime, zenzero, pepe nero','Nessuno',1,'https://example.com/lama-affilata.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(12,'Premeditazione','Caffè espresso e cardamomo con scaglie di cioccolato nero','Ogni dettaglio è stato pianificato. Il caffè espresso e il cardamomo si combinano con freddezza e precisione, lasciando sul palato un impronta indelebile. Non ci sono testimoni, solo sapore.',3.50,'Latte, panna, zucchero, caffè espresso, cardamomo, cioccolato fondente 80%','Latte',1,'https://example.com/premeditazione.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(13,'Firma del Killer','Ciliegia nera e pepe rosa con striatura rossa','Ogni grande killer lascia la sua firma. La ciliegia nera e il pepe rosa lasciano sul palato un segno inconfondibile: dolce, piccante, pericoloso. Riconosci il gusto... se ci riesci.',3.50,'Latte, panna, zucchero, ciliegia nera, pepe rosa','Latte',1,'https://example.com/firma-killer.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(14,'Movente Oscuro','Cioccolato nero e sale marino con caramello bruciato','Dietro ogni grande crimine si nasconde un movente. Dietro questo gelato si nasconde un equilibrio perfetto tra il cioccolato nero, il sale marino e il caramello bruciato. Scoprilo a tuo rischio.',4.00,'Latte, panna, zucchero, cacao 85%, sale marino, caramello','Latte',1,'https://example.com/movente-oscuro.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(15,'Senza Tracce','Vaniglia nera e carbone con glassa invisibile','Non lascia prove, non lascia tracce. Solo un ricordo indelebile sul palato. La vaniglia nera e il carbone vegetale creano un gusto misterioso che scompare prima che tu possa descriverlo. Il crimine perfetto.',4.50,'Latte, panna, zucchero, vaniglia nera, carbone vegetale','Latte',1,'https://example.com/senza-tracce.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(16,'Piano di Dominazione','Nocciola e oro alimentare con scaglie croccanti','Ogni villain ha un piano. Il nostro prevede nocciola tostata, oro alimentare e scaglie croccanti di cioccolato. Grandioso, elaborato, irresistibile. Esattamente come ogni piano di dominazione mondiale che si rispetti.',4.00,'Latte, panna, zucchero, nocciola tostata, oro alimentare, cioccolato','Latte, frutta a guscio',1,'https://example.com/piano-dominazione.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(17,'Risata Malvagia','Passion fruit e peperoncino con colatura viola','HAHAHAHA! Un gusto sopra le righe, eccessivo, esagerato. Il passion fruit e il peperoncino creano un contrasto esplosivo che ti strapperà una risata... o una lacrima. Forse entrambe.',3.50,'Latte, panna, zucchero, passion fruit, peperoncino','Latte',1,'https://example.com/risata-malvagia.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(18,'Tana Segreta','Mandorla affumicata e miele nero con cuore nascosto','Ogni super cattivo ha la sua tana segreta. La nostra è fatta di mandorla affumicata e miele nero, con un cuore nascosto al cioccolato fondente che si rivela solo all ultimo morso. Lo trovavi?',4.00,'Latte, panna, zucchero, mandorla affumicata, miele nero, cioccolato fondente','Latte, frutta a guscio',1,'https://example.com/tana-segreta.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(19,'Ego Smisurato','Triplo cioccolato con granella dorata e caramello','Perché accontentarsi quando puoi avere tutto? Triplo cioccolato, granella dorata e caramello salato in un unico gelato monumentale. Per chi sa di meritare il meglio, anche se deve conquistarselo con la forza.',4.50,'Latte, panna, zucchero, cioccolato al latte, cioccolato fondente, cioccolato bianco, caramello salato, oro alimentare','Latte',1,'https://example.com/ego-smisurato.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(20,'Ultima Mossa','Fico nero e rum con glassa lacca nera','La mossa finale, quella che nessuno si aspetta. Il fico nero e il rum si fondono in un gusto audace e raffinato, avvolto in una glassa lacca nera lucidissima. Il colpo di scena che non dimenticherai.',5.00,'Latte, panna, zucchero, fico nero, rum, cacao','Latte',1,'https://example.com/ultima-mossa.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(21,'Morso al Collo','Melograno e ciliegia nera con striature rosse','Dolce come la seduzione, intenso come un morso nel buio. Il melograno e la ciliegia nera si fondono in un rosso sangue irresistibile. Attento: dopo il primo assaggio, vorrai ancora.',3.50,'Latte, panna, zucchero, melograno, ciliegia nera','Latte',1,'https://example.com/morso-al-collo.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(22,'Cripta dei Sapori','Mirtillo nero e liquirizia con cuore cremoso','Nascosto nelle profondità di una cripta secolare, questo gelato custodisce un segreto antico. Il mirtillo nero e la liquirizia avvolgono un cuore cremoso che si svela lentamente, come un vampiro che emerge dall oscurità.',3.50,'Latte, panna, zucchero, mirtillo nero, liquirizia','Latte',1,'https://example.com/cripta-sapori.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(23,'Alba Proibita','Arancia rossa e rosa con polvere di rubino','L unica alba che un vampiro può permettersi: quella di una granita all arancia rossa. Fresca, intensa, proibita. Il colore del tramonto in versione gelato, per chi non può aspettare il calar del sole.',2.50,'Acqua, zucchero, arancia rossa di Sicilia, acqua di rose','Nessuno',1,'https://example.com/alba-proibita.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(24,'Eterno Ritorno','Frutta del drago e ibisco con glassa cremisi','Come ogni vampiro che si rispetti, questo gusto ritorna sempre. La frutta del drago e l ibisco creano un rosso cremisi ipnotico e seducente, con una dolcezza che dura in eterno... o quasi.',4.00,'Latte, panna, zucchero, frutta del drago, ibisco','Latte',1,'https://example.com/eterno-ritorno.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43'),(25,'Sangue Blu','Mirtillo selvatico e violetta con glassa indaco','Non tutti i vampiri sono uguali. Quelli di sangue blu hanno gusti raffinati e irraggiungibili. Il mirtillo selvatico e la violetta creano un gelato elegante e misterioso, degno solo dei palati più nobili. Sei all altezza?',5.00,'Latte, panna, zucchero, mirtillo selvatico, violetta, colorante naturale indaco','Latte',1,'https://example.com/sangue-blu.jpg','2026-06-10 15:06:43','2026-06-10 15:06:43');
