LOCK TABLES `reviews` WRITE;
/*!40000 ALTER TABLE `reviews` DISABLE KEYS */;
INSERT INTO `reviews` VALUES (1,'Esperienza unica','Il colore verde fosforescente cattura subito l attenzione. Il sapore è intenso e originale. Perfetto per chi cerca qualcosa di diverso dal solito.',4,'Stefano P.','2024-11-22',11,1),(2,'Ottimo rapporto qualità prezzo','Per il prezzo che si paga la qualità è ottima. Porzioni generose e gusto intenso. Lo consiglio a tutti gli amanti del pistacchio.',4,'Irene V.','2024-11-22',7,1),(3,'Non fa per me','Non sono un fan della menta nei gelati e questo ha un sapore molto deciso. Capisco che piaccia ma personalmente preferisco altri gusti della gelateria.',2,'Marco R.','2024-11-15',3,1),(4,'Un capolavoro di orrore e sapore','Non mi aspettavo di trovare qualcosa di così buono con un aspetto così inquietante. Il pistacchio e la menta insieme sono una combinazione vincente. Tornerò sicuramente!',5,'Massimo T.','2024-12-01',15,1),(5,'Verde come l invidia, buono come pochi','Il colore mi ha fatto esitare ma poi ho ceduto. Ottimo gusto, la menta non sovrasta il pistacchio. Forse un po troppo dolce per i miei gusti ma nel complesso ottimo.',4,'Andrea N.','2024-08-29',8,1),(6,'Nella media','Niente di straordinario rispetto ad altre gelaterie artigianali che conosco. Il tema horror è divertente ma il gusto potrebbe essere più audace.',3,'Elisa P.','2024-06-15',2,1),(7,'Il migliore della gelateria','Ho provato quasi tutto il menu ma il Cervello Marcio resta il mio preferito. Ogni volta che vengo in zona mi fermo qui apposta.',5,'Tommaso S.','2024-11-01',22,1),(8,'Buono ma non eccezionale','Il gusto è piacevole ma il nome promette qualcosa di più estremo. Mi aspettavo qualcosa di più particolare. Comunque si mangia volentieri.',3,'Claudio V.','2024-11-08',4,1),(9,'Assolutamente da provare','Ero scettico sulla combinazione pistacchio e menta ma mi sono dovuto ricredere. Un equilibrio perfetto tra i due sapori. Consigliatissimo!',5,'Beatrice G.','2024-09-12',18,1),(10,'Zombificante nel senso migliore','Dopo averlo assaggiato non riesco a smettere di pensarci. Torno ogni settimana solo per questo. Il pistacchio di qualità si sente eccome.',5,'Paola G.','2024-08-29',29,1),(11,'Sorprendente','Mia figlia lo ha scelto per il colore e io l ho assaggiato per curiosità. Ora lo ordiniamo entrambi ogni volta. Un vero successo di famiglia.',5,'Nicola C.','2024-07-18',14,1),(12,'Molto soddisfatto','Qualità degli ingredienti ottima, si sente. Il carbone vegetale non altera il sapore ma regala quel colore da brivido. Perfetto per il tema.',4,'Enrico L.','2024-11-08',9,2),(13,'Troppo amaro per me','Per chi ama il cioccolato fondente è perfetto. Io lo trovo un po troppo intenso ma capisco il target. La presentazione è spettacolare.',3,'Massimo T.','2024-08-08',5,2),(14,'Il mio preferito in assoluto','Ogni volta che vengo porto qualcuno di nuovo solo per vedere la loro faccia quando ordinano qualcosa chiamato Putrefazione. Il gusto poi li convince sempre.',5,'Marco R.','2024-07-25',25,2),(15,'Ritorno garantito','La terza volta che ordino questo e non mi stanca mai. Ogni cucchiaio è una conferma di quanto sia buono. Complimenti al gelatiere.',5,'Pietro A.','2024-10-24',20,2),(16,'Oscuro e irresistibile','Non me lo aspettavo così buono. Il biscotto al carbone aggiunge una texture croccante perfetta. Il cioccolato è intenso senza essere amaro.',4,'Sara B.','2024-11-08',12,2),(17,'Non per tutti','Il cioccolato è davvero molto intenso e il retrogusto del carbone si sente. Per i puristi del cioccolato fondente potrebbe essere interessante ma non fa per me.',2,'Andrea N.','2024-09-19',4,2),(18,'Sorprendentemente buono','Il nome mi aveva convinto a scegliere altro ma ho ceduto alla curiosità. Sono contento di averlo fatto. Gusto intenso e avvolgente.',4,'Claudio V.','2024-09-26',13,2),(19,'Presentazione da 10','Il colore nero assoluto è semplicemente spettacolare. Il sapore è all altezza. Ottimo gelato per chi ama i gusti decisi.',4,'Alessia T.','2024-09-19',16,2),(20,'Nero come l anima, buono come il peccato','Il carbone vegetale gli dà un colore assolutamente inquietante. Il cioccolato fondente è di qualità eccellente. Una delle migliori coppette che abbia mai mangiato.',5,'Matteo L.','2024-10-24',19,2),(21,'Indimenticabile','Ho portato i miei amici dall estero e questo è stato il gelato che ha impressionato di più. Sia per l aspetto che per il gusto.',5,'Federica A.','2024-09-19',31,2),(22,'Colazione perfetta','L ho presa la mattina con la brioche e devo dire che è stata una colazione indimenticabile. La acidità del lime sveglia i sensi.',5,'Beatrice G.','2024-08-08',19,3),(23,'Originale e rinfrescante','I semi di chia danno una texture interessante che non mi aspettavo in una granita. Scelta coraggiosa e azzeccata.',4,'Chiara V.','2024-10-10',7,3),(24,'Colori da zombie approvati','Il rosso dell anguria e il verde del lime creano un effetto visivo perfetto per il tema. Il sapore è all altezza dell aspetto.',4,'Marco R.','2024-06-15',8,3),(25,'Buona ma non originale','Il gusto anguria e lime è piacevole ma lo si trova anche altrove. L aggiunta dei semi di chia è interessante. Nel complesso una buona granita.',3,'Emanuele R.','2024-11-15',6,3),(26,'Ritorno ogni settimana','Da quando l ho scoperta la prendo ogni sabato mattina. È diventata il mio rituale settimanale. Fantastica.',5,'Anna S.','2024-12-10',14,3),(27,'Consigliata','L ho consigliata a tutti i miei amici e sono tornati a ringraziarmi. Un gusto fresco e originale che piace a tutti.',4,'Irene V.','2024-09-19',10,3),(28,'Nella media','Granita piacevole ma niente di straordinario. Il tema horror è divertente ma il gusto potrebbe osare di più.',3,'Fabio D.','2024-06-15',2,3),(29,'La migliore granita in zona','Ho girato tutte le gelaterie della zona e questa granita non ha rivali. La qualità dell anguria si sente e il lime è dosato perfettamente.',5,'Giulia T.','2024-09-19',23,3),(30,'Il mio nuovo preferito','Ero venuto per altro ma questo mi ha conquistato al primo assaggio. Ora è il mio ordine fisso ogni volta che vengo.',5,'Simone F.','2024-06-22',22,4),(31,'Non fa per me','La combinazione mela e zenzero è troppo particolare per i miei gusti. Apprezzo la creatività ma preferisco gusti più classici.',2,'Alessia T.','2024-08-01',3,4),(32,'Perfetto','Ogni elemento è dosato alla perfezione. Lo zenzero non sovrasta, la mela è presente, la glassa aggiunge quel tocco horror impagabile.',5,'Martina D.','2024-12-10',17,4),(33,'Unico nel suo genere','Non ho mai mangiato un gelato simile. La combinazione di sapori è audace e riuscita. La gelateria merita rispetto per la creatività.',5,'Stefano P.','2024-07-03',28,4),(34,'Lo zenzero è troppo presente','Per me lo zenzero copre troppo il sapore della mela. Chi ama lo zenzero lo adorerà, io lo trovo un po eccessivo.',3,'Elena G.','2024-10-17',4,4),(35,'Interessante','Un gusto che fa discutere. Non per tutti ma sicuramente originale. Vale la pena provarlo almeno una volta.',3,'Emanuele R.','2024-07-18',5,4),(36,'Il contagio più dolce che esista','La mela verde e lo zenzero sono una combinazione che non avevo mai provato in un gelato. Risultato sorprendente e originale.',5,'Daniele S.','2024-07-25',21,4),(37,'Piccante e fresco insieme','Lo zenzero si sente bene senza essere invadente. La mela verde bilancia perfettamente. La glassa fosforescente è uno spettacolo.',4,'Fabio D.','2024-11-15',13,4),(38,'Visivamente spettacolare','Il verde fosforescente attira tutti gli sguardi. Il sapore è all altezza della presentazione. Ottimo gelato per i più avventurosi.',4,'Luca M.','2024-12-01',15,4),(39,'Coraggioso e riuscito','Ci vuole coraggio a proporre questi abbinamenti. Complimenti al gelatiere per aver osato. Il risultato è molto interessante.',4,'Cristina B.','2024-09-05',9,4),(40,'Limited edition da non perdere','Ho sentito che è disponibile solo per poco e sono venuto apposta. Non mi ha deluso. Speriamo che la rimettano in produzione.',5,'Fabio D.','2024-08-01',26,5),(41,'Fenomenale','La limited edition che aspettavo. Non delude le aspettative anzi le supera. Il cuore cremoso è una piacevole sorpresa ad ogni morso.',5,'Valentina R.','2024-07-18',22,5),(42,'Esperienza unica','Il tema della resurrezione è reso perfettamente nel contrasto tra i frutti di bosco scuri e il cuore bianco di vaniglia. Poetico e buonissimo.',4,'Chiara V.','2024-07-18',11,5),(43,'Vale il prezzo','Per una limited edition il prezzo è giusto. La qualità degli ingredienti è evidente. Il cuore cremoso è una trovata geniale.',4,'Massimo T.','2024-07-03',14,5),(44,'Consigliato vivamente','L ho preso su consiglio del personale e non me ne sono pentito. Qualità eccellente e presentazione impeccabile.',4,'Monica L.','2024-08-01',16,5),(45,'Il migliore in assoluto','Ho assaggiato tutto il menu nel corso delle mie visite e questo è il vertice assoluto. La limited edition è una scelta saggia perché crea attesa.',5,'Beatrice G.','2024-11-08',41,5),(46,'Buono ma sopravvalutato','È buono ma non capisco tutto questo entusiasmo. I frutti di bosco sono ottimi ma il cuore di vaniglia non mi ha sorpreso più di tanto.',3,'Sara B.','2024-07-10',7,5),(47,'Capolavoro','Chi ha inventato questo gelato è un genio. Ogni elemento ha un senso e il risultato finale è straordinario. Bravi!',5,'Francesco P.','2024-07-25',37,5),(48,'Indimenticabile','L ho mangiato una volta sola e ci penso ancora. Spero davvero che lo riportino perché è qualcosa di speciale.',5,'Emanuele R.','2024-08-29',29,5),(49,'Troppo esotico','Non conoscevo il lychee e devo dire che non è di mio gradimento. Ma è un problema mio di gusti personali, non della qualità.',2,'Nicola C.','2024-12-10',3,6),(50,'Sorprendentemente buono','Non sono un fan del cocco di solito ma questo gelato mi ha convertito. Il lychee aggiunge una nota esotica irresistibile.',4,'Paola G.','2024-12-01',12,6),(51,'Ottima scelta','Fresco, leggero e originale. Il tema fantasma è reso perfettamente sia visivamente che nel gusto evanescente.',4,'Irene V.','2024-07-25',8,6),(52,'Elegante','Un gelato raffinato e originale. La combinazione cocco e lychee funziona molto bene. Perfetto per una serata estiva.',4,'Serena N.','2024-10-17',10,6),(53,'Mi ha stregato','L ho scelto quasi per caso e ora è uno dei miei preferiti. La leggerezza del gusto è il suo punto di forza.',5,'Claudio V.','2024-07-03',17,6),(54,'Carino','Piacevole ma non memorabile. Il tema horror è reso in modo troppo soft per i miei gusti. Preferisco qualcosa di più audace.',3,'Luca M.','2024-11-08',4,6),(55,'Etereo e delizioso','Il cocco e il lychee insieme sono una rivelazione. Leggero, fresco, con una dolcezza delicata. Perfetto per il tema fantasmi.',5,'Beatrice G.','2024-12-10',19,6),(56,'Il cono fantasma perfetto','La glassa bianca lattiginosa è uno spettacolo visivo. Il sapore è all altezza. Leggero e rinfrescante, sparisce in bocca come un fantasma.',5,'Martina D.','2024-09-26',24,6),(57,'Consigliato','Un gelato che sa sorprendere con la sua leggerezza. Ottimo per chi non ama i gusti troppo intensi.',4,'Daniele S.','2024-08-22',9,6),(58,'Troppo delicato','Per chi ama i gusti intensi questo potrebbe essere troppo leggero. Il cocco e il lychee sono piacevoli ma poco incisivi.',3,'Valentina R.','2024-07-25',5,6),(59,'Fantastico','Gioco di parole voluto. Uno dei migliori della gelateria. La qualità degli ingredienti è impeccabile.',5,'Matteo L.','2024-07-10',21,6),(60,'Raffinato','Un gelato per palati sofisticati. Non cerca di sorprendere con contrasti estremi ma con una armonia perfetta di sapori.',4,'Andrea N.','2024-11-15',11,7),(61,'Perfetto','Ogni elemento è in equilibrio perfetto. Non troppo dolce, non troppo neutro. Una coppetta che finisce sempre troppo in fretta.',5,'Veronica M.','2024-06-22',23,7),(62,'Consigliatissimo','L ho preso su consiglio di un amico e sono contento. Un gusto che sa essere elegante senza essere pretenzioso.',4,'Chiara V.','2024-09-05',6,7),(63,'Sorprendente nella semplicità','A volte la semplicità è la scelta più coraggiosa. Questo gelato lo dimostra.',4,'Anna S.','2024-11-01',7,7),(64,'Ritorno garantito','Uno di quei gelati che non stancano mai. La semplicità ben eseguita batte sempre la complessità mal riuscita.',5,'Cristina B.','2024-11-08',18,7),(65,'Il mio preferito tra i fantasmi','Ho provato tutti i gusti del tema fantasmi e questo è il mio preferito. La semplicità è la sua forza.',5,'Camilla F.','2024-11-08',19,7),(66,'Delicato come un soffio','La mandorla e lo yogurt insieme sono una combinazione che non mi aspettavo così buona. La vaniglia completa il tutto alla perfezione.',5,'Matteo L.','2024-10-03',16,7),(67,'Anonimo','Non riesco a ricordarmelo dopo averlo mangiato. Sarà buono ma non lascia il segno. Per una gelateria horror è un difetto.',2,'Silvia M.','2024-11-15',2,7),(68,'Nella media','Buono ma non straordinario. La mandorla potrebbe essere più presente.',3,'Elisa P.','2024-08-29',3,7),(69,'Ottimo','La qualità dello yogurt si sente. La mandorla è croccante al punto giusto. Un gelato onesto e ben fatto.',4,'Simone F.','2024-06-22',8,7),(70,'Troppo semplice','Il gusto è piacevole ma per una gelateria horror mi aspettavo qualcosa di più audace. Manca il brivido.',3,'Nicola C.','2024-09-19',4,7),(71,'Eccellente','La vaniglia bourbon si sente ed è di qualità. Gelato artigianale nel senso migliore del termine.',5,'Stefano P.','2024-10-24',14,7),(72,'Incantevole','Un gusto che evoca esattamente quello che promette il nome. Nebbiosa, misteriosa, irresistibile.',5,'Davide C.','2024-06-15',18,8),(73,'Perfetta come dessert serale','Il nome dice tutto. È la granita perfetta da gustare la sera, magari dopo cena. Leggera e aromatica.',4,'Elena G.','2024-10-10',10,8),(74,'Buonissima','Fresca, aromatica e originale. Il limone bianco la rende meno acida delle granite tradizionali.',4,'Riccardo M.','2024-08-15',8,8),(75,'Interessante','Un gusto da provare almeno una volta. Non diventerà il mio fisso ma apprezzo la creatività.',3,'Silvia M.','2024-11-15',4,8),(76,'Poetica e buonissima','Il limone bianco e i fiori di sambuco creano un gusto floreale unico. È come mangiare un tramonto estivo.',5,'Nicola C.','2024-07-18',21,8),(77,'Troppo floreale','I fiori di sambuco sono molto presenti e il gusto risulta quasi profumato. Non è il mio tipo ma capisco che piaccia.',3,'Paola G.','2024-10-24',5,8),(78,'Molto particolare','Chi cerca qualcosa di diverso dalla solita granita deve assolutamente provare questa. Coraggio premiato.',4,'Giulia T.','2024-09-12',9,8),(79,'Straordinaria','La qualità dei fiori di sambuco si sente immediatamente. Una granita artigianale nel vero senso della parola.',5,'Sara B.','2024-07-18',22,8),(80,'Non fa per me','I fiori di sambuco danno un sapore troppo erbaceo per i miei gusti. Preferisco granite più tradizionali.',2,'Marco R.','2024-08-08',3,8),(81,'Consigliato','Un gelato che sa sorprendere. Per chi ama i gusti freschi e originali è una scelta obbligata.',4,'Massimo T.','2024-09-26',7,9),(82,'Visivamente incredibile','La colatura lattiginosa è uno spettacolo. Il gusto melone e menta è fresco e originale. Un gusto speciale che merita il nome.',5,'Laura C.','2024-10-03',24,9),(83,'Il gusto speciale più speciale','Tra tutti i gusti speciali questo è il mio preferito. Il melone bianco è dolce e la menta lo rinfresca perfettamente.',5,'Federica A.','2024-07-25',31,9),(84,'Stupendo','Ogni elemento funziona alla perfezione. La presentazione, il gusto, la texture. Un gusto speciale davvero speciale.',5,'Sara B.','2024-07-10',26,9),(85,'Nella media','Buono ma non eccezionale. Il nome e la presentazione promettono più di quanto il gusto mantenga.',3,'Paola G.','2024-08-15',3,9),(86,'Originale e buono','Una combinazione che non avrei mai pensato di ordinare ma che mi ha convinto. La curiosità premia.',4,'Silvia M.','2024-08-01',8,9),(87,'Molto buono','La menta non sovrasta il melone come temevo. Un equilibrio riuscito tra due sapori molto diversi.',4,'Chiara V.','2024-10-03',11,9),(88,'Non mi ha convinto','Il melone bianco nel gelato non è di mio gradimento. Ma è chiaramente un problema di gusti personali.',2,'Cristina B.','2024-10-10',4,9),(89,'Eccellente','La qualità degli ingredienti è impeccabile. Il melone è fresco e la menta è naturale. Artigianalità vera.',5,'Emanuele R.','2024-09-19',17,9),(90,'Strano nel senso migliore','Non sapevo cosa aspettarmi da qualcosa chiamato Ectoplasma. Il risultato mi ha piacevolmente sorpreso.',4,'Marco R.','2024-11-01',15,9),(91,'Non per me','L abbinamento pesca e rosmarino è troppo insolito per i miei gusti. Preferisco i classici.',2,'Marco R.','2024-11-08',3,10),(92,'Ottimo','Una limited edition che dimostra quanto la gelateria sappia osare. Risultato eccellente.',4,'Roberto F.','2024-06-22',14,10),(93,'Poetico','Il nome è perfetto. Un gusto delicato e malinconico, come se stesse svanendo. Un esperienza quasi emotiva.',4,'Andrea N.','2024-07-25',12,10),(94,'Indimenticabile','L ho mangiato una sola volta e continuo a pensarci. Un gelato che lascia il segno.',5,'Alessia T.','2024-11-22',31,10),(95,'Il rosmarino è invadente','Per me il rosmarino prende troppo il sopravvento sulla pesca. Ma capisco che per alcuni sia il punto di forza.',3,'Tommaso S.','2024-09-26',7,10),(96,'Limited edition da sogno','La pesca bianca e il rosmarino sono una combinazione che non dimenticherò. Speriamo che la riportino.',5,'Paola G.','2024-10-24',28,10),(97,'Il migliore tra i gusti speciali','Ho assaggiato tutti i gusti speciali e questo è il vertice. La limited edition si sente nella cura degli ingredienti.',5,'Francesco P.','2024-07-03',35,10),(98,'Sorprendentemente erbaceo','Il rosmarino nel gelato mi sembrava strano ma funziona benissimo con la pesca. Una scelta coraggiosa e riuscita.',4,'Pietro A.','2024-09-12',16,10),(99,'Originale e riuscita','Una granita che osa e vince. Per i palati coraggiosi è una scelta obbligata.',4,'Roberto F.','2024-07-03',9,11),(100,'Interessante','Un gusto da provare almeno una volta. Non lo ordinerò sempre ma sono contento di averlo scoperto.',3,'Silvia M.','2024-11-15',5,11),(101,'Perfetta','Il nome descrive esattamente il gusto. Affilata, precisa, memorabile. Una granita che non dimentichi.',5,'Riccardo M.','2024-09-19',23,11),(102,'Troppo aggressiva','Vive pienamente all altezza del nome ma per me è troppo piccante. Per chi ama i gusti estremi è perfetta.',3,'Serena N.','2024-07-25',6,11),(103,'Eccellente','Ogni ingrediente ha un ruolo preciso. Il pepe nero finale è il colpo di scena che non ti aspetti.',5,'Giulia T.','2024-12-01',18,11),(104,'Troppo intensa','Per i miei gusti è troppo. Lime, zenzero e pepe insieme sono davvero molto. Rispetto la scelta ma non fa per me.',2,'Paola G.','2024-10-03',4,11),(105,'Tagliente al punto giusto','Il lime e lo zenzero creano una granita che sveglia i sensi. Il pepe nero finale è il tocco geniale.',5,'Irene V.','2024-07-10',20,11),(106,'La granita più coraggiosa','Non esiste granita più coerente con il tema serial killer di questa. Tagliente, precisa, senza pietà.',5,'Matteo L.','2024-06-22',27,11),(107,'Troppo amaro','Il caffè è molto presente e l insieme risulta amaro per i miei gusti. Per i fan del caffè amaro è perfetto.',3,'Roberto F.','2024-09-05',7,12),(108,'Il mio ordine fisso','Da quando l ho scoperto non ordino altro. Il cardamomo aggiunge una nota speziata irresistibile.',5,'Luca M.','2024-11-01',30,12),(109,'Pianificato alla perfezione','Il caffè e il cardamomo sono una combinazione da manuale. Le scaglie di cioccolato completano il tutto.',5,'Serena N.','2024-08-15',25,12),(110,'Nella media','Buono ma non memorabile quanto mi aspettavo. Forse le aspettative erano troppo alte.',3,'Laura C.','2024-08-01',4,12),(111,'Eccellente','Il caffè espresso è di qualità superiore. Si sente immediatamente. Un gelato che rispetta gli ingredienti.',5,'Francesco P.','2024-08-22',22,12),(112,'Consigliato','Per chi ama i gusti intensi e non banali questo è il gelato giusto.',4,'Valentina R.','2024-07-18',8,12),(113,'Non fa per me','Sono un amante del caffè ma nel gelato trovo questa combinazione troppo intensa. Questione di gusti.',2,'Camilla F.','2024-08-29',5,12),(114,'Sofisticato','Un gelato per palati adulti. Niente dolcezze banali, solo sapori decisi e ben calibrati.',4,'Andrea N.','2024-09-26',12,12),(115,'Capolavoro','Ogni elemento è al suo posto. Il cioccolato fondente finale è il tocco che eleva il gelato.',5,'Emanuele R.','2024-07-25',19,12),(116,'Per veri amanti del caffè','Intenso, aromatico, deciso. Se ami il caffè questo è il gelato che fa per te.',4,'Sara B.','2024-08-08',16,12),(117,'Molto buono','Il cardamomo è dosato perfettamente. Non sovrasta il caffè ma lo arricchisce. Una scelta felice.',4,'Veronica M.','2024-11-22',10,12),(118,'Coraggioso','Ci vuole coraggio a mettere il pepe in un gelato. Coraggio premiato da un risultato eccellente.',4,'Massimo T.','2024-06-22',7,13),(119,'Molto buono','La ciliegia nera è di qualità eccellente. Il pepe rosa aggiunge carattere senza essere eccessivo.',4,'Andrea N.','2024-09-12',9,13),(120,'Interessante','Un gusto da provare. Non sarà il mio fisso ma l esperienza vale.',3,'Alessia T.','2024-10-10',4,13),(121,'Fenomenale','Il cono con questo gusto è la combinazione perfetta. La croccantezza della cialda completa il tutto.',5,'Nicola C.','2024-10-10',18,13),(122,'Audace e riuscito','Il pepe rosa nella ciliegia sembrava strano ma funziona perfettamente. Complimenti per la creatività.',4,'Luca M.','2024-08-01',14,13),(123,'Troppo piccante','Non amo il piccante nei dolci. Il pepe rosa è davvero molto presente. Non fa per me.',2,'Francesco P.','2024-09-12',3,13),(124,'Straordinario','Ogni morso è una scoperta. Prima la ciliegia poi il piccante del pepe. Un gioco di sapori perfetto.',5,'Camilla F.','2024-08-08',25,13),(125,'Originale','Una combinazione che non avevo mai provato in un gelato. La curiosità è stata premiata.',4,'Anna S.','2024-08-01',11,13),(126,'Il mio preferito del tema','Tra tutti i gusti serial killer questo è il mio assoluto preferito. Il contrasto dolce piccante è geniale.',5,'Paola G.','2024-09-12',29,13),(127,'La firma più dolce che esi